def head(title, desc, url, img='assets/images/drone-poster.jpg', keywords='Austin real estate investor, Austin residential redevelopment, Austin property buyer'):
    schema='''<script type="application/ld+json">{"@context":"https://schema.org","@type":"RealEstateAgent","name":"ABCO Residential Group","url":"https://abcoresidential.com","areaServed":["Austin TX","Round Rock TX","Cedar Park TX","Leander TX","Georgetown TX","Pflugerville TX"],"description":"Residential investment and redevelopment company acquiring, renovating and repositioning homes across Greater Austin.","email":"info@abcoresidential.com"}</script>'''
    return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{title}</title><meta name="description" content="{desc}"><meta name="keywords" content="{keywords}"><link rel="canonical" href="{BASE}/{url}"><meta property="og:title" content="{title}"><meta property="og:description" content="{desc}"><meta property="og:type" content="website"><meta property="og:url" content="{BASE}/{url}"><meta property="og:image" content="{BASE}/{img}"><meta name="twitter:card" content="summary_large_image"><meta name="twitter:title" content="{title}"><meta name="twitter:description" content="{desc}"><meta name="theme-color" content="#0D1B34"><link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;700;800;900&family=Montserrat:wght@700;800;900&display=swap" rel="stylesheet"><link rel="stylesheet" href="styles.css"><script async src="https://www.googletagmanager.com/gtag/js?id={GA}"></script><script>window.dataLayer=window.dataLayer||[];function gtag(){{dataLayer.push(arguments);}}gtag('js',new Date());gtag('config','{GA}');</script><script>!function(f,b,e,v,n,t,s){{if(f.fbq)return;n=f.fbq=function(){{n.callMethod?n.callMethod.apply(n,arguments):n.queue.push(arguments)}};if(!f._fbq)f._fbq=n;n.push=n;n.loaded=!0;n.version='2.0';n.queue=[];t=b.createElement(e);t.async=!0;t.src=v;s=b.getElementsByTagName(e)[0];s.parentNode.insertBefore(t,s)}}(window,document,'script','https://connect.facebook.net/en_US/fbevents.js');fbq('init','{PIXEL}');fbq('track','PageView');</script>{schema}</head><body>{NAV}'''

def write(name,title,desc,body,keywords=None):
    root.joinpath(name).write_text(head(title,desc,name,keywords=keywords or 'Austin real estate investor, Austin residential redevelopment, Austin property buyer')+body+FOOT+'</body></html>',encoding='utf-8')

